function ArxivFinderWidget() {
  const [query, setQuery] = React.useState('');
  const [results, setResults] = React.useState([]);

  function search() {
    if (!query.trim()) return;
    setResults([
      { title: 'Attention Is All You Need', authors: 'Vaswani et al.', year: '2017' },
      { title: 'Deep Residual Learning for Image Recognition', authors: 'He et al.', year: '2016' },
      { title: 'Generative Adversarial Networks', authors: 'Goodfellow et al.', year: '2014' }
    ]);
  }

  return (
    <div style={{ fontFamily: 'system-ui, sans-serif', padding: 16, background: '#0f172a', color: '#e2e8f0', borderRadius: 12, height: '100%', display: 'flex', flexDirection: 'column' }}>
      <h3 style={{ margin: 0, marginBottom: 12 }}>arXiv Finder</h3>
      <div style={{ display: 'flex', gap: 8, marginBottom: 12 }}>
        <input
          value={query}
          onChange={(e) => setQuery(e.target.value)}
          onKeyDown={(e) => e.key === 'Enter' && search()}
          placeholder="Search papers..."
          style={{ flex: 1, padding: '8px 10px', borderRadius: 6, border: '1px solid #334155', background: '#1e293b', color: '#e2e8f0', fontFamily: 'system-ui, sans-serif' }}
        />
        <button
          onClick={search}
          style={{ padding: '8px 14px', borderRadius: 6, border: 'none', background: '#3b82f6', color: '#fff', fontWeight: 600, cursor: 'pointer', fontFamily: 'system-ui, sans-serif' }}
        >
          Search
        </button>
      </div>
      <div style={{ flex: 1, overflow: 'auto' }}>
        {results.map((r, i) => (
          <div key={i} style={{ background: '#1e293b', padding: 10, borderRadius: 8, marginBottom: 8 }}>
            <div style={{ fontSize: 13, fontWeight: 600, marginBottom: 4 }}>{r.title}</div>
            <div style={{ fontSize: 11, color: '#94a3b8' }}>{r.authors} — {r.year}</div>
          </div>
        ))}
      </div>
    </div>
  );
}
render(<ArxivFinderWidget/>);
